  ('dietitian-moex-10145', 'dietitian', 'dietitian-moex-095-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '若某餐飲食中含動物性維生素A有300 IU，α-胡蘿蔔素600微克，β-胡蘿蔔素660微克，請問其相當可攝取多少微 克視網醇當量？', '["150", "200", "250", "300"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:55+00:00", "source_pdf_sha1": "277a16535430", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095030", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "095", "exam_name": "095年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
